import React, { useState } from 'react';
import { Menu, X, ChevronRight, Home, Book, FileText, Settings, Sun, Moon, FormInput } from 'lucide-react';

const Layout = ({ children, darkMode, toggleDarkMode }) => {
  const [isOpen, setIsOpen] = useState(false);

  const toggleSidebar = () => {
    setIsOpen(!isOpen);
  };

  return (
    <div className={`h-screen flex overflow-hidden ${darkMode ? 'dark' : ''}`}>
      {/* Overlay for mobile */}
      {isOpen && (
        <div
          className="fixed inset-0 bg-black bg-opacity-50 z-20 lg:hidden"
          onClick={toggleSidebar}
        />
      )}

      {/* Sidebar */}
      <div
        className={`fixed inset-y-0 left-0 transform ${
          isOpen ? 'translate-x-0' : '-translate-x-full'
        } lg:transform-none lg:relative w-64 bg-white dark:bg-gray-900 border-r border-gray-200 dark:border-gray-700 transition-transform duration-300 ease-in-out z-30`}
      >
        <div className="h-full flex flex-col">
          {/* Sidebar Header */}
          <div className="h-16 flex items-center justify-between px-4 border-b border-gray-200 dark:border-gray-700">
            <h1 className="text-xl font-bold bg-gradient-to-r from-blue-600 to-purple-600 bg-clip-text text-transparent">
              Wiki Paralegal
            </h1>
            <button
              onClick={toggleSidebar}
              className="lg:hidden p-2 rounded-md hover:bg-gray-100 dark:hover:bg-gray-800"
            >
              <X className="h-5 w-5 text-gray-500 dark:text-gray-400" />
            </button>
          </div>

          {/* Sidebar Navigation */}
          <nav className="flex-1 overflow-y-auto py-4">
            <div className="px-4 space-y-1">
              <SidebarItem icon={Home} text="Home" to="/" />
              <SidebarItem icon={Book} text="Pleadings" to="/pleadings" />
              <SidebarItem icon={FileText} text="Motions" to="/motions" />
              <SidebarItem icon={FormInput} text="Forms" to="/forms" />
              
              {/* Subsections */}
              <div className="pl-4 mt-2 space-y-1">
                <SidebarSubItem text="Templates" to="/resources/templates" />
                <SidebarSubItem text="Guidelines" to="/resources/guidelines" />
                <SidebarSubItem text="Information" to="/resources/information" />
              </div>
            </div>
          </nav>

          {/* Sidebar Footer */}
          <div className="border-t border-gray-200 dark:border-gray-700 p-4">
            <button
              onClick={toggleDarkMode}
              className="flex items-center justify-between w-full px-4 py-2 text-sm font-medium text-gray-700 dark:text-gray-200 hover:bg-gray-100 dark:hover:bg-gray-800 rounded-md"
            >
              <span>{darkMode ? 'Light Mode' : 'Dark Mode'}</span>
              {darkMode ? (
                <Sun className="h-4 w-4" />
              ) : (
                <Moon className="h-4 w-4" />
              )}
            </button>
          </div>
        </div>
      </div>

      {/* Main Content */}
      <div className="flex-1 flex flex-col overflow-hidden bg-gray-50 dark:bg-gray-900">
        {/* Top Bar */}
        <header className="h-16 flex items-center justify-between px-4 bg-white dark:bg-gray-800 border-b border-gray-200 dark:border-gray-700">
          <button
            onClick={toggleSidebar}
            className="lg:hidden p-2 rounded-md hover:bg-gray-100 dark:hover:bg-gray-700"
          >
            <Menu className="h-5 w-5 text-gray-500 dark:text-gray-400" />
          </button>
        </header>

        {/* Page Content */}
        <main className="flex-1 overflow-y-auto">
          <div className="container mx-auto px-4 py-6">
            {children}
          </div>
        </main>
      </div>
    </div>
  );
};

// Sidebar Item Component
const SidebarItem = ({ icon: Icon, text, to }) => (
  <a
    href={to}
    className="flex items-center px-4 py-2 text-sm font-medium text-gray-700 dark:text-gray-200 hover:bg-gray-100 dark:hover:bg-gray-800 rounded-md"
  >
    <Icon className="h-5 w-5 mr-3 text-gray-500 dark:text-gray-400" />
    {text}
  </a>
);

// Sidebar Sub Item Component
const SidebarSubItem = ({ text, to }) => (
  <a
    href={to}
    className="flex items-center pl-12 py-2 text-sm font-medium text-gray-700 dark:text-gray-200 hover:bg-gray-100 dark:hover:bg-gray-800 rounded-md"
  >
    <ChevronRight className="h-4 w-4 mr-2 text-gray-500 dark:text-gray-400" />
    {text}
  </a>
);

export default Layout;
